import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { 
  listenAuction, 
  startAuction, 
  closeAuction, 
  listenPlayers, 
  addPlayer, 
  deletePlayer,
  resetAllWins,
  clearAllRecords
} from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });

  // Form State
  const [newPlayer, setNewPlayer] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(setAuction),
      listenPlayers((data) => {
        // FILTER: Remove Admin from the list entirely so only family members show
        const onlyFamily = data.filter(p => !p.isAdmin);
        setPlayers(onlyFamily);
      })
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleAddPlayer = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await addPlayer(newPlayer.email, newPlayer.password, newPlayer.name);
      toast.success("Player added successfully!");
      setNewPlayer({ name: '', email: '', password: '' });
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (playerId, playerName) => {
    if (window.confirm(`Are you sure you want to delete ${playerName}?`)) {
      try {
        await deletePlayer(playerId);
        toast.success("Player removed.");
      } catch (err) {
        toast.error("Failed to delete player.");
      }
    }
  };

  const handleMaintenanceReset = async () => {
    const confirmText = "⚠️ CRITICAL: This will wipe ALL auction records and reset ALL winners for a brand new cycle. Are you absolutely sure?";
    if (!window.confirm(confirmText)) return;

    try {
      await clearAllRecords();
      await resetAllWins();
      toast.success("System completely reset for a fresh cycle!");
    } catch (err) {
      toast.error("Reset failed: " + err.message);
    }
  };

  return (
    <div className="page-wide">
      <div className="navbar">
        <div className="navbar-brand">👑 Admin Dashboard</div>
        <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1.2fr 1.8fr', gap: '20px', marginBottom: '20px' }}>

        {/* SIDEBAR: FORMS */}
        <div className="sidebar">
          {/* ADD PLAYER FORM */}
          <div className="card">
            <h3 className="card-title">Add New Family Member</h3>
            <form onSubmit={handleAddPlayer} style={{ marginTop: '15px' }}>
              <div className="form-group">
                <label className="form-label">Full Name</label>
                <input type="text" className="form-input" required value={newPlayer.name}
                  onChange={e => setNewPlayer({...newPlayer, name: e.target.value})} />
              </div>
              <div className="form-group">
                <label className="form-label">Email</label>
                <input type="email" className="form-input" required value={newPlayer.email}
                  onChange={e => setNewPlayer({...newPlayer, email: e.target.value})} />
              </div>
              <div className="form-group">
                <label className="form-label">Password</label>
                <input type="password" className="form-input" required value={newPlayer.password}
                  onChange={e => setNewPlayer({...newPlayer, password: e.target.value})} />
              </div>
              <button className="btn btn-primary btn-full" disabled={loading}>
                {loading ? "Creating..." : "Add Member"}
              </button>
            </form>
          </div>

          {/* MAINTENANCE SECTION */}
          <div className="card" style={{ border: '1px solid rgba(255, 77, 77, 0.3)' }}>
            <h3 className="card-title" style={{ color: '#ff4d4d' }}>System Maintenance</h3>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '15px' }}>
              Use this button ONLY to reset the whole group for a new 10-month cycle.
            </p>
            <button className="btn btn-danger btn-full btn-sm" onClick={handleMaintenanceReset}>
              Wipe All Records & Reset Wins
            </button>
          </div>
        </div>

        {/* MAIN: AUCTION CONTROL */}
        <div className="main-content">
          <div className="card" style={{ textAlign: 'center', minHeight: '300px', display: 'flex', flexDirection: 'column', justifyContent: 'center' }}>
            <h3 className="card-title">Live Auction Status</h3>
            {auction?.active ? (
              <div style={{ marginTop: '20px' }}>
                <div className="badge badge-green">LIVE SESSION</div>
                <h1 style={{ fontSize: '3.5rem', color: 'var(--gold)', margin: '10px 0' }}>
                  ₹{auction.currentBid?.toLocaleString('en-IN')}
                </h1>
                <p>Current Bidder: <b>{auction.currentBidderName || "None"}</b></p>
                <button className="btn btn-danger btn-full" style={{marginTop: '25px'}} onClick={() => closeAuction(auction)}>
                  End Auction & Finalize Winner
                </button>
              </div>
            ) : (
              <div style={{ marginTop: '20px' }}>
                <div className="form-group" style={{ maxWidth: '200px', margin: '0 auto 15px' }}>
                  <label className="form-label">Monthly BC Amount</label>
                  <input type="number" className="form-input" value={settings.monthlyAmount} 
                    onChange={e => setSettings({...settings, monthlyAmount: Number(e.target.value)})} />
                </div>
                <button className="btn btn-primary btn-full" onClick={() => startAuction(settings)}>
                  Start New Monthly Auction
                </button>
              </div>
            )}
          </div>

          {/* PLAYER LIST */}
          <div className="card" style={{ marginTop: '20px' }}>
            <h3 className="card-title">Family Members ({players.length})</h3>
            <div style={{ marginTop: '15px', overflowX: 'auto' }}>
              <table className="records-table">
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Status</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {players.map(p => (
                    <tr key={p.id}>
                      <td>
                        <div style={{fontWeight: 600}}>{p.name}</div>
                        <div style={{fontSize: '0.7rem', color: 'var(--text-muted)'}}>{p.email}</div>
                      </td>
                      <td>
                        {p.hasWon ? 
                          <span className="badge badge-green">Won ({p.wonMonth})</span> : 
                          <span className="badge badge-muted">Eligible</span>
                        }
                      </td>
                      <td>
                        <button 
                          className="btn btn-danger btn-sm" 
                          onClick={() => handleDelete(p.id, p.name)}
                        >
                          🗑️
                        </button>
                      </td>
                    </tr>
                  ))}
                  {players.length === 0 && (
                    <tr>
                      <td colSpan="3" style={{ textAlign: 'center', padding: '20px', color: 'var(--text-muted)' }}>
                        No family members added yet.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}
